// PATCH: Cover owner-only local output files for financial command data.
func TestCreatePrivateOutputFileUsesOwnerOnlyPermissions(t *testing.T) {
	outputPath := filepath.Join(t.TempDir(), "exports", "transactions.jsonl")
	f, err := createPrivateOutputFile(outputPath)
	if err != nil {
		t.Fatalf("createPrivateOutputFile: %v", err)
	}
	if _, err := f.Write([]byte(`{"transactions":[]}`)); err != nil {
		_ = f.Close()
		t.Fatalf("write output: %v", err)
	}
	if err := f.Close(); err != nil {
		t.Fatalf("close output: %v", err)
	}

	assertOwnerOnlyCLIPath(t, filepath.Dir(outputPath))
	assertOwnerOnlyCLIPath(t, outputPath)
}

