func assertOwnerOnlyCLIPath(t *testing.T, path string) {
	t.Helper()
	info, err := os.Stat(path)
	if err != nil {
		t.Fatalf("stat %s: %v", path, err)
	}
	if got := info.Mode().Perm(); got&0o077 != 0 {
		t.Fatalf("%s mode = %#o, want no group/other permissions", path, got)
	}
}
